import { useContext, useEffect, useMemo, useState } from "react";
import { AuthContext } from "./AuthContext";
import "./styles/club_header.css";
import ClubHeader from "./components/ClubHeader";

export default function ClubDetail() {
    const { user } = useContext(AuthContext);

    const [club, setClub] = useState(null);
    const [news, setNews] = useState([]);
    const [members, setMembers] = useState([]);
    const [pending, setPending] = useState([]);
    const [users, setUsers] = useState([]);

    const [title, setTitle] = useState("");
    const [content, setContent] = useState("");

    const [myStatus, setMyStatus] = useState({
        isMember: false,
        hasPending: false,
        requestId: null,
    });

    const [openMember, setOpenMember] = useState(null);
    const [hash, setHash] = useState(window.location.hash);
    const [loading, setLoading] = useState(true);
    const [err, setErr] = useState("");

    // Keep hash in React state (so tab + title updates work)
    useEffect(() => {
        const onHashChange = () => setHash(window.location.hash);
        window.addEventListener("hashchange", onHashChange);
        return () => window.removeEventListener("hashchange", onHashChange);
    }, []);

    const clubId = useMemo(() => {
        const m = (hash || "").match(/^#\/clubs\/(\d+)/i);
        return m ? Number(m[1]) : null;
    }, [hash]);

    // userId -> user map for labels
    const userMap = useMemo(() => {
        const map = new Map();
        (users || []).forEach((u) => map.set(u.id, u));
        return map;
    }, [users]);

    const userLabel = (uid) => {
        const u = userMap.get(uid);
        if (!u) return `User #${uid}`;
        return `${u.username} (${u.email})`;
    };

    // Sorted members
    const sortedMembers = useMemo(() => {
        const rank = (r) => (r === "LEADER" ? 0 : r === "CO_LEADER" ? 1 : 2);
        return [...members].sort((a, b) => rank(a.role || "MEMBER") - rank(b.role || "MEMBER"));
    }, [members]);

    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";
    const isLeader = !!user && members.some((m) => m.userId === user.id && m.role === "LEADER");
    const isCoLeader = !!user && members.some((m) => m.userId === user.id && m.role === "CO_LEADER");

    const canSeeActionMenu = !!user && (isAdmin || isLeader || isCoLeader);
    const canPostNews = isAdmin || isLeader || isCoLeader;
    const canApproveRequests = isAdmin || isLeader; // your backend allows co-leader too, but you said you want admin/leader only

    // membership derived correctly (status OR members list)
    const membership = useMemo(() => {
        const isMemberFromList = !!user && members.some((m) => m.userId === user.id);
        return {
            isMember: myStatus.isMember || isMemberFromList,
            hasPending: myStatus.hasPending,
            isLeader,
        };
    }, [myStatus, members, user?.id, isLeader]);

    // Leader names for header
    const leaderNames = useMemo(() => {
        return sortedMembers.filter((m) => m.role === "LEADER").map((m) => userLabel(m.userId));
    }, [sortedMembers, users]);

    // Page title (club + active tab)
    useEffect(() => {
        if (!club?.name) return;

        const tab = (hash.split("/").pop() || "overview").toLowerCase();
        const allowed = ["overview", "members", "news", "stats", "matches"];
        const label = allowed.includes(tab) ? tab.toUpperCase() : "OVERVIEW";

        document.title = `${club.name} – ${label} | Clubs`;
    }, [club?.name, hash]);

    // Initial load: club/news/members/users + status
    useEffect(() => {
        if (!clubId) return;

        let cancelled = false;
        setLoading(true);
        setErr("");

        (async () => {
            try {
                const [cRes, nRes, mRes, uRes] = await Promise.all([
                    fetch(`/api/clubs/${clubId}`),
                    fetch(`/api/clubs/${clubId}/news`),
                    fetch(`/api/clubs/${clubId}/members`),
                    fetch(`/api/users`),
                ]);

                const c = await cRes.json().catch(() => null);
                const n = await nRes.json().catch(() => []);
                const m = await mRes.json().catch(() => []);
                const u = await uRes.json().catch(() => []);

                if (cancelled) return;

                if (!cRes.ok || !c) {
                    setErr(c?.message || "Club not found");
                    setClub(null);
                    setNews([]);
                    setMembers([]);
                    setUsers([]);
                    setPending([]);
                    return;
                }

                setClub(c);
                setNews(Array.isArray(n) ? n : []);
                setMembers(Array.isArray(m) ? m : []);
                setUsers(Array.isArray(u) ? u : u?.content || []);

                // status (if logged in)
                if (user?.email) {
                    const stRes = await fetch(
                        `/api/clubs/${clubId}/status?requesterEmail=${encodeURIComponent(user.email)}`
                    );
                    const st = await stRes.json().catch(() => ({
                        isMember: false,
                        hasPending: false,
                        requestId: null,
                    }));
                    if (!cancelled) setMyStatus(stRes.ok ? st : { isMember: false, hasPending: false, requestId: null });
                } else {
                    setMyStatus({ isMember: false, hasPending: false, requestId: null });
                }
            } catch (e) {
                if (!cancelled) setErr("Failed to load club page");
            } finally {
                if (!cancelled) setLoading(false);
            }
        })();

        return () => {
            cancelled = true;
        };
    }, [clubId, user?.email]);

    // Fetch pending requests once permissions are known
    useEffect(() => {
        if (!clubId) return;
        if (!user?.email) {
            setPending([]);
            return;
        }
        if (!canApproveRequests) {
            setPending([]);
            return;
        }

        let cancelled = false;
        fetch(`/api/clubs/${clubId}/join-requests?requesterEmail=${encodeURIComponent(user.email)}`)
            .then((r) => (r.ok ? r.json() : []))
            .then((p) => {
                if (!cancelled) setPending(Array.isArray(p) ? p : []);
            })
            .catch(() => {
                if (!cancelled) setPending([]);
            });

        return () => {
            cancelled = true;
        };
    }, [clubId, user?.email, canApproveRequests]);

    // Actions
    const requestJoinClub = async () => {
        if (!user) return alert("Please log in to request to join.");

        const res = await fetch(
            `/api/clubs/${clubId}/join?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "POST" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to send request");

        const st = await fetch(
            `/api/clubs/${clubId}/status?requesterEmail=${encodeURIComponent(user.email)}`
        ).then((r) => r.json());

        setMyStatus(st);
    };

    const cancelJoinRequest = async () => {
        if (!user || !myStatus.requestId) return;

        const res = await fetch(
            `/api/clubs/${clubId}/join-requests/${myStatus.requestId}?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );
        const b = await res.json().catch(() => ({}));
        if (!res.ok) return alert(b.message || "Failed to cancel request");

        setMyStatus((prev) => ({ ...prev, hasPending: false, requestId: null }));
        setPending((prev) => prev.filter((p) => p.id !== myStatus.requestId && p.userId !== user.id));
    };

    const leaveClub = async () => {
        if (!user) return;
        if (isLeader) {
            alert("You are the club leader. Transfer leadership before leaving.");
            return;
        }
        if (!window.confirm("Are you sure you want to leave this club?")) return;

        const res = await fetch(
            `/api/clubs/${clubId}/leave?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "POST" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to leave club");

        setMyStatus({ isMember: false, hasPending: false, requestId: null });
        setMembers((prev) => prev.filter((m) => m.userId !== user.id));
    };

    const decide = async (requestId, decision) => {
        const url =
            `/api/clubs/${clubId}/join-requests/${requestId}/decision` +
            `?requesterEmail=${encodeURIComponent(user.email)}` +
            `&decision=${decision}`;

        const res = await fetch(url, { method: "POST" });
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed");

        const [m, p] = await Promise.all([
            fetch(`/api/clubs/${clubId}/members`).then((r) => r.json()),
            fetch(`/api/clubs/${clubId}/join-requests?requesterEmail=${encodeURIComponent(user.email)}`).then((r) =>
                r.json()
            ),
        ]);

        setMembers(Array.isArray(m) ? m : []);
        setPending(Array.isArray(p) ? p : []);
    };

    const postNews = async (e) => {
        e.preventDefault();
        if (!title.trim() || !content.trim()) return;

        const res = await fetch(
            `/api/clubs/${clubId}/news?requesterEmail=${encodeURIComponent(user.email)}`,
            {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ title: title.trim(), content: content.trim() }),
            }
        );

        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed");

        setNews((prev) => [body, ...prev]);
        setTitle("");
        setContent("");
    };

    const deleteNews = async (newsId) => {
        const res = await fetch(
            `/api/clubs/${clubId}/news/${newsId}?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );
        const b = await res.json().catch(() => ({}));
        if (!res.ok) return alert(b.message || "Failed");
        setNews((prev) => prev.filter((n) => n.id !== newsId));
    };

    // Role / moderation fixes
    const makeLeader = async (targetUserId) => {
        const res = await fetch(
            `/api/clubs/${clubId}/members/${targetUserId}/make-leader?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "POST" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to set leader");

        setMembers((prev) =>
            prev.map((m) => {
                if (m.userId === targetUserId) return { ...m, role: "LEADER" };
                if (m.role === "LEADER") return { ...m, role: "CO_LEADER" }; // or MEMBER if you prefer
                return m;
            })
        );
        setOpenMember(null);
    };

    const makeCoLeader = async (targetUserId) => {
        const res = await fetch(
            `/api/clubs/${clubId}/members/${targetUserId}/make-co_leader?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "POST" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to promote");

        setMembers((prev) => prev.map((m) => (m.userId === targetUserId ? { ...m, role: "CO_LEADER" } : m)));
        setOpenMember(null);
    };

    const makeMember = async (targetUserId) => {
        const res = await fetch(
            `/api/clubs/${clubId}/members/${targetUserId}/make-member?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "POST" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to demote");

        setMembers((prev) => prev.map((m) => (m.userId === targetUserId ? { ...m, role: "MEMBER" } : m)));
        setOpenMember(null);
    };

    const kickMember = async (targetUserId) => {
        if (!window.confirm("Remove this member from the club?")) return;

        const res = await fetch(
            `/api/clubs/${clubId}/members/${targetUserId}?requesterEmail=${encodeURIComponent(user.email)}`,
            { method: "DELETE" }
        );
        const body = await res.json().catch(() => ({}));
        if (!res.ok) return alert(body.message || "Failed to remove member");

        setMembers((prev) => prev.filter((m) => m.userId !== targetUserId));
        setOpenMember(null);
    };

    // Render guards
    if (!clubId) {
        return (
            <div style={s.page}>
                <a href="#/clubs" style={s.backLink}>
                    ← Back
                </a>
            </div>
        );
    }

    if (loading) {
        return (
            <div style={s.page}>
                <div style={s.card}>Loading…</div>
            </div>
        );
    }

    if (err) {
        return (
            <div style={s.page}>
                <div style={s.card}>{err}</div>
            </div>
        );
    }

    if (!club) {
        return (
            <div style={s.page}>
                <div style={s.card}>Club not found.</div>
            </div>
        );
    }

    return (
        <div className="page">
            <ClubHeader
                club={{
                    id: club.id,
                    name: club.name,
                    shortName: club.tag,
                    website: club.website,
                    twitter: club.twitter,
                    country: club.country,
                    logoUrl: club.logoUrl,
                    description: club.description,
                }}
                leaders={leaderNames}
                membership={membership}     // IMPORTANT: correct derived membership
                activeTab="overview"
                onJoin={requestJoinClub}
                onLeave={leaveClub}
                onCancelRequest={cancelJoinRequest}
            />

            <div style={s.grid}>
                {/* News */}
                <div>
                    <div style={s.sectionHeader}>
                        <h3 style={s.h3}>Club News</h3>
                    </div>

                    {canPostNews && (
                        <form onSubmit={postNews} style={s.newsForm}>
                            <input
                                placeholder="Title"
                                value={title}
                                onChange={(e) => setTitle(e.target.value)}
                                required
                                style={s.input}
                            />
                            <textarea
                                placeholder="Content"
                                value={content}
                                onChange={(e) => setContent(e.target.value)}
                                required
                                style={s.textarea}
                            />
                            <div style={{ textAlign: "right" }}>
                                <button type="submit" style={s.primaryBtn}>
                                    Post
                                </button>
                            </div>
                        </form>
                    )}

                    {news.length === 0 && <div style={s.card}>No news yet.</div>}

                    {news.map((n) => (
                        <div key={n.id} style={s.card}>
                            <div style={s.cardHead}>
                                <strong style={{ fontSize: 16 }}>{n.title}</strong>
                                {canPostNews && (
                                    <button onClick={() => deleteNews(n.id)} style={s.dangerBtn}>
                                        Delete
                                    </button>
                                )}
                            </div>
                            <div style={{ whiteSpace: "pre-wrap", lineHeight: 1.5 }}>{n.content}</div>
                            <div style={s.meta}>{n.createdAt ? new Date(n.createdAt).toLocaleString() : ""}</div>
                        </div>
                    ))}
                </div>

                {/* Members & Pending */}
                <div>
                    <div style={s.sectionHeader}>
                        <h3 style={s.h3}>Members</h3>
                    </div>

                    <div style={s.card}>
                        <ul style={s.list}>
                            {sortedMembers.map((m) => {
                                const isThisLeader = m.role === "LEADER";
                                const isThisCoLeader = m.role === "CO_LEADER";
                                const isThisMember = !isThisLeader && !isThisCoLeader;
                                const isSelf = user && m.userId === user.id;
                                const menuOpen = openMember === m.userId;

                                const badge = isThisLeader ? (
                                    <span style={s.badgeLeader}>LEADER</span>
                                ) : isThisCoLeader ? (
                                    <span style={s.badgeCoLeader}>CO-LEADER</span>
                                ) : (
                                    <span style={s.badge}>MEMBER</span>
                                );

                                const canKickThisUser =
                                    isAdmin || (isLeader && !isThisLeader) || (isCoLeader && isThisMember);

                                const canPromoteToCoLeader = (isLeader || isAdmin) && isThisMember;
                                const canDemoteToMember =
                                    (isLeader && isThisCoLeader) || (isAdmin && !isSelf && isThisCoLeader);

                                return (
                                    <li key={m.id} style={{ ...s.listItem, position: "relative" }}>
                    <span
                        onClick={() => setOpenMember(menuOpen ? null : m.userId)}
                        style={{ cursor: canSeeActionMenu ? "pointer" : "default" }}
                    >
                      {userLabel(m.userId)}
                    </span>

                                        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                            {badge}
                                            {canSeeActionMenu && !isSelf && (
                                                <button
                                                    onClick={() => setOpenMember(menuOpen ? null : m.userId)}
                                                    style={s.primaryBtnSm}
                                                    title="Manage member"
                                                >
                                                    ⋮
                                                </button>
                                            )}
                                        </div>

                                        {canSeeActionMenu && !isSelf && menuOpen && (
                                            <div style={s.menu}>
                                                {isAdmin && !isThisLeader && (
                                                    <button style={s.menuItem} onClick={() => makeLeader(m.userId)}>
                                                        Make Leader (Admin)
                                                    </button>
                                                )}

                                                {canPromoteToCoLeader && (
                                                    <button style={s.menuItem} onClick={() => makeCoLeader(m.userId)}>
                                                        Promote to Co-leader
                                                    </button>
                                                )}

                                                {canDemoteToMember && (
                                                    <button style={s.menuItem} onClick={() => makeMember(m.userId)}>
                                                        Demote to Member
                                                    </button>
                                                )}

                                                {canKickThisUser && (
                                                    <button style={{ ...s.menuItem, color: "#b00020" }} onClick={() => kickMember(m.userId)}>
                                                        Kick
                                                    </button>
                                                )}
                                            </div>
                                        )}
                                    </li>
                                );
                            })}
                            {sortedMembers.length === 0 && <li style={s.muted}>No members yet.</li>}
                        </ul>
                    </div>

                    {canApproveRequests && (
                        <>
                            <div style={s.sectionHeader}>
                                <h3 style={s.h3}>Pending Requests</h3>
                            </div>

                            <div style={s.card}>
                                {pending.length === 0 && <div style={s.muted}>No pending requests.</div>}

                                {pending.map((r) => (
                                    <div key={r.id} style={s.pendingRow}>
                                        <div>
                                            <div style={{ fontWeight: 600 }}>{userLabel(r.userId)}</div>
                                            <div style={s.meta}>Request ID: {r.id}</div>
                                        </div>
                                        <div style={s.actions}>
                                            <button onClick={() => decide(r.id, "approve")} style={s.primaryBtnSm}>
                                                Approve
                                            </button>
                                            <button onClick={() => decide(r.id, "reject")} style={s.dangerBtnSm}>
                                                Reject
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </>
                    )}
                </div>
            </div>
        </div>
    );
}

