        display: "inline-block",
        marginBottom: 10,
    },
    card: {
        background: "#fff",
        border: "1px solid #e6e6e6",
        borderRadius: 12,
        padding: 16,
        boxShadow: "0 8px 24px rgba(0,0,0,0.06)",
        marginBottom: 12,
    },
    grid: { display: "grid", gridTemplateColumns: "2fr 1fr", gap: 16, alignItems: "start" },
    sectionHeader: { display: "flex", justifyContent: "space-between", alignItems: "center", margin: "8px 0" },
    h3: { margin: 0 },
    newsForm: { ...cardLike(), display: "grid", gap: 10, marginBottom: 12 },
    input: { width: "90%", padding: "10px 12px", borderRadius: 10, border: "1px solid #ddd", outline: "none" },
    textarea: {
        width: "90%",
        minHeight: 110,
        padding: "10px 12px",
        borderRadius: 10,
        border: "1px solid #ddd",
        outline: "none",
        resize: "vertical",
    },
    primaryBtn: button("#0b57d0", "#fff"),
    dangerBtn: button("#b00020", "#fff"),
    primaryBtnSm: button("#0b57d0", "#fff", true),
    dangerBtnSm: button("#b00020", "#fff", true),
    cardHead: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 },
    meta: { opacity: 0.7, fontSize: 12, marginTop: 6 },
    list: { listStyle: "none", padding: 0, margin: 0, display: "grid", gap: 8 },
    listItem: { padding: "8px 10px", border: "1px solid #eee", borderRadius: 10, display: "flex", justifyContent: "space-between", alignItems: "center" },
    muted: { color: "#777" },
    badge: { background: "#eef2f7", color: "#374151", padding: "2px 8px", borderRadius: 999, fontSize: 12 },
    badgeLeader: { background: "#fde68a", color: "#7c4a00", padding: "2px 8px", borderRadius: 999, fontSize: 12, fontWeight: 700 },
    badgeCoLeader: { background: "#dbeafe", color: "#1e40af", padding: "2px 8px", borderRadius: 999, fontSize: 12, fontWeight: 600 },
    pendingRow: { border: "1px solid #eee", borderRadius: 10, padding: 10, display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 },
    actions: { display: "flex", gap: 8 },
    menu: {
        position: "absolute",
        right: 10,
        top: "100%",
        marginTop: 6,
        background: "#fff",
        border: "1px solid #ddd",
        borderRadius: 10,
        boxShadow: "0 8px 24px rgba(0,0,0,0.08)",
        padding: 8,
        display: "grid",
        gap: 6,
