        minWidth: 180,
    },
    menuItem: { background: "transparent", border: "none", textAlign: "left", padding: "6px 8px", borderRadius: 8, cursor: "pointer" },
};

function button(bg, fg, small = false) {
    return {
        background: bg,
        color: fg,
        border: "none",
        borderRadius: 10,
        padding: small ? "6px 10px" : "8px 12px",
        cursor: "pointer",
        boxShadow: "0 2px 10px rgba(0,0,0,0.08)",
    };
}
function cardLike() {
    return {
        background: "#fff",
        border: "1px solid #e6e6e6",
        borderRadius: 12,
        padding: 12,
        boxShadow: "0 8px 24px rgba(0,0,0,0.06)",
    };
}
